        #region 记录AWG日志

        /// <summary>
        /// 打印日志
        /// </summary>
        /// <param name="msg"></param>
        private static void WriteLog(String msg)
        {
            if (!Directory.Exists(_AWGLogPath))
            {
                Directory.CreateDirectory(_AWGLogPath);
            }
            var filename = $"{_AWGLogPath}{_AWGInitLog}";
            File.AppendAllText(filename, $"{DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss.ffff")}：{msg}{Environment.NewLine}");
        }

        /// <summary>
        /// 清除日志
        /// </summary>
        private static void ClearTiAdcCaliLog()
        {
            String[] tiadccalilogpaths = Directory.GetFiles(_AWGLogPath);
            foreach (var item in tiadccalilogpaths)
            {
                String filename = Path.GetFileName(item);
                if (filename.StartsWith("AWGInitLog") && filename != _AWGInitLog)
                {
                    File.Delete(item);
                }
            }
        }

        #endregion

        private static ArbWfmGenOptions MakeDefaultOptions()
        {
            return new ArbWfmGenOptions(false, ArbWfmType.Sinusoid, WfmGenImpedance.HighZ, 0, 0, 0, 0, 0, TriggerSource.Inside, WfmRampType.Rise);
        }
        private static void WriteAwgBySpi(int regAddr, UInt16 data)
        {
            WriteAwgBySpi((UInt16)regAddr, data);
        }
        private static void WriteAwgBySpi(UInt16 regAddr, UInt16 data)
        {
            HdIO.WriteReg(ProcBdReg.W.Awg_awg_wr_ctrl, 0x04);
            HdIO.WriteReg(ProcBdReg.W.Awg_awg_data_in, data);
            // 低8位地址
            UInt16 addrCtrl = (UInt16)(regAddr & 0xffff);
            // cs为0时，发送一次，赋初值
            HdIO.WriteReg(ProcBdReg.W.Awg_awg_addr_ctrl, addrCtrl);
            // cs置1，再发送一次
            addrCtrl = (UInt16)(regAddr | (0x0001 << 8));
            HdIO.WriteReg(ProcBdReg.W.Awg_awg_addr_ctrl, addrCtrl);
            //HdIO.Sleep(1);
            HdIO.WriteReg(ProcBdReg.W.Awg_awg_wr_ctrl, 0x05);
        }

