        /// <summary>
        /// 初始化挡位状态
        /// </summary>
        private static void ArbWfmGenAttDic_Init()
        {
            if (ArbWfmGenAttDic != null && ArbWfmGenAttDic.Count == 0)
            {
                ArbWfmGenAttDic = new Dictionary<ChannelId, ushort>();
                ArbWfmGenAttDic.Add(ChannelId.AWG1, 0);
                ArbWfmGenAttDic.Add(ChannelId.AWG2, 0);
                ArbWfmGenAttDic.Add(ChannelId.AWG3, 0);
                ArbWfmGenAttDic.Add(ChannelId.AWG4, 0);
            }
        }
        private static void LogWave_Init()
        {
            //log_wave = new ushort[constDataDeep];
            //for (int i = 0; i < logdata.Length; i++)
            //{
            //    if (i >= constDataDeep)
            //    {
            //        break;
            //    }
            //    //log_wave[i] = (ushort)logdata[i];
            //    log_wave[i] = (ushort)Math.Exp(i);
            //}
            log_wave = new UInt16[moduDataDeep];
            for (uint i = 0; i < moduDataDeep; i++)
            {
                pointData[i] = (32767.0) * Math.Log(i); ;  //量化
                                                           //pointData[i] = i * (-32767.0) / constDataDeep;  //量化
                log_wave[i] = (UInt16)pointData[i];  //整形
            }
        }
        private static void LineWave_Init()
        {
            line_wave = new UInt16[moduDataDeep];
            for (uint i = 0; i < moduDataDeep; i++)
            {
                pointData[i] = i * (32767.0) / moduDataDeep;  //量化
                                                              //pointData[i] = i * (-32767.0) / constDataDeep;  //量化
                line_wave[i] = (UInt16)pointData[i];  //整形

                //sendData[i] = (uint)pointData[i];  //整形
                //WriteAwgBySpi(SHARE_FPGA_CONFIG_HDATA_L, (UInt16)(((UInt64)sendData[i] & 0xff)), false);
                //WriteAwgBySpi(SHARE_FPGA_CONFIG_HDATA_H, (UInt16)(((UInt64)sendData[i] >> 8 & 0xff)), false);
            }
        }
