        #region 波形函数

        public static void SineWave(int datalen = constDataDeep) //正弦波
        {
            var tmpPointData = new double[datalen];
            for (uint i = 0; i < datalen; i++)
            {
                tmpPointData[i] = Math.Sin((double)i * 2.0 * Math.PI / datalen);//生成波形数据
            }
            Normalization(ref tmpPointData);
            for (uint i = 0; i < datalen; i++)
            {
                tmpPointData[i] = (double)(tmpPointData[i] * 32767.0);  //量化
                sendData[i] = (UInt16)tmpPointData[i];  //整形
                WriteAwgBySpi(AWG_WRITE_DATA1, (UInt16)(sendData[i] & 0xff));
                WriteAwgBySpi(AWG_WRITE_DATA2, (UInt16)(sendData[i] >> 8 & 0xff));
            }
        }

