        private static void ArbPointByPoint(ChannelId channelId)
        {
            UInt16 setData = channelId == ChannelId.AWG1 ? AWG1_DDR_WRITE_DATA : AWG2_DDR_WRITE_DATA;
            var data = channelId == ChannelId.AWG1 ? Hd.UIMessage!.ArbWfmGen![0].ArbWfmData : Hd.UIMessage!.ArbWfmGen![1].ArbWfmData;

            if (data == null || data.Count == 0)
            {
                return;
            }
            double[] pointBypointDatas = new double[data.Count];
            for (int i = 0; i < data.Count; i++)
            {
                pointBypointDatas[i] = data[i];
            }
            Normalization(ref pointBypointDatas);
            WriteAwgBySpi(AWG_DDR_WRITE_SET, setData);
            WriteAwgBySpi(AWG_DDR_WRITE_ENABLE, 1);
            if (pointBypointDatas == null || pointBypointDatas.Length == 0)
            {
                return;
            }

            var nextAddr = AWG_DDR_DATA_START;
            int sendTimes;
            if (pointBypointDatas.Length % AWG_DDR_WRITE_COUNT == 0)
            {
                sendTimes = 1;
            }
            else
            {
                sendTimes = AWG_DDR_WRITE_COUNT;
            }
            for (int i = 0; i < sendTimes * pointBypointDatas.Length; i++)
            {
                var sendData = (UInt64)(pointBypointDatas[i % pointBypointDatas.Length] * 32767.0); //量化 整形
                                                                                                    //var sendData = (UInt64)(pointBypointDatas[i % pointBypointDatas.Length]); // 整形
                                                                                                    //WriteAwgBySpi(nextAddr, (ushort)(sendData));
                WriteAwgBySpi(nextAddr, (ushort)(sendData & 0xFF));
                WriteAwgBySpi(nextAddr + 1, (ushort)(sendData >> 8 & 0xFF));
                nextAddr += 2;
                //nextAddr += 1;
                if (nextAddr > AWG_DDR_DATA_END)
                {
                    nextAddr = AWG_DDR_DATA_START;
                }
            }
            WriteAwgBySpi(AWG_DDR_WRITE_ENABLE, 0);
        }
        public static void ArbitryModeWave(ChannelId channelId)
        {
            var data = channelId == ChannelId.AWG1 ? Hd.UIMessage!.ArbWfmGen![0].ModArbWfmData : Hd.UIMessage!.ArbWfmGen![1].ModArbWfmData;
            if (data == null)
            {
                return;
            }
            var count = data.Count > moduDataDeep ? moduDataDeep : data.Count;
            if (data.Count > moduDataDeep)
            {
                double rate = (double)data.Count / moduDataDeep;
                for (int i = 0; i < moduDataDeep; i++)
                {
                    pointData[i] = data[(int)((double)i * rate)];
                }
            }
            else
            {
                for (int i = 0; i < count; i++)
                {
                    pointData[i] = data[i];
                }
                if (count < moduDataDeep)
                {
                    for (int i = count; i < moduDataDeep; i++)
                    {
                        pointData[i] = data[i % count];
                    }
                }
            }

            Normalization(ref pointData);

            for (int i = 0; i < count; i++)
            {
                pointData[i] = (pointData[i] * 32767.0); //量化
                sendData[i] = (UInt16)pointData[i];  //整形
                WriteAwgBySpi(AWG_WRITE_DATA1, (UInt16)(sendData[i] & 0xff));
                WriteAwgBySpi(AWG_WRITE_DATA2, (UInt16)(sendData[i] >> 8 & 0xff));
            }
        }
        public static void ArbitryWave(ChannelId channelId)
        {
            var data = channelId == ChannelId.AWG1 ? Hd.UIMessage!.ArbWfmGen![0].ArbWfmData : Hd.UIMessage!.ArbWfmGen![1].ArbWfmData;
            if (data == null)
            {
                return;
            }
            var count = data.Count > constDataDeep ? constDataDeep : data.Count;
            if (data.Count > constDataDeep)
            {
                double rate = (double)data.Count / constDataDeep;
                for (int i = 0; i < constDataDeep; i++)
                {
                    pointData[i] = data[(int)((double)i * rate)];
                }
            }
            else
            {
                for (int i = 0; i < count; i++)
                {
                    pointData[i] = data[i];
                }
                if (count < constDataDeep)
                {
                    for (int i = count; i < constDataDeep; i++)
                    {
                        pointData[i] = data[i % count];
                    }
                }
            }

            Normalization(ref pointData);

            for (int i = 0; i < count; i++)
            {
                pointData[i] = (pointData[i] * 32767.0); //量化
                sendData[i] = (UInt16)pointData[i];  //整形
                WriteAwgBySpi(AWG_WRITE_DATA1, (UInt16)(sendData[i] & 0xff));
                WriteAwgBySpi(AWG_WRITE_DATA2, (UInt16)(sendData[i] >> 8 & 0xff));
            }
        }

