        internal static void Config()
        {
            if (!Hd.CurrProduct!.HardwareConfig!.bExistAWGModule)
                return;
            if (_CalStatus != WfmGenCalStatus.OFF)
            {
                return;
            }

            ArbWfmGenAttDic_Init();

            int times = 0;

            AWG_HD_Data_Send_Locked = true;

            bool auxOut = false;//外触发开关
            ChannelId channel = ChannelId.AWG1;//外触发通道
            bool channelActive = false;
            optionsChanged = false;
            for (int i = 0; i < Hd.UIMessage!.ArbWfmGen!.Length; i++)
            {
                var arbWfmGenOption = Hd.UIMessage!.ArbWfmGen[i];
                ClearAWGProtect(arbWfmGenOption.GenChannelId);
                while (AWG_HD_InQuery_Protect && times < 10)
                {
                    Thread.Sleep(1);
                    times++;
                }
                if (times >= 10)
                {
                    return;
                }
                channelActive = channelActive || arbWfmGenOption.Active;
                if (arbWfmGenOptions[i] != arbWfmGenOption)
                {
                    if (AWG_Actions[i] != arbWfmGenOption.Active)
                    {
                        AWG_Actions[i] = arbWfmGenOption.Active;
                        optionsChanged = true;
                    }
                    ConfigAWG(arbWfmGenOption.GenChannelId, arbWfmGenOption);
                    if (!AWG_Actions[i])
                    {
                        CalibSetAMP(0);
                        CalibWfmOffset(0);
                        AWG_BasicWaveType(arbWfmGenOption.GenChannelId, ArbWfmType.DC, false);
                        AWG_CH_CTRL(arbWfmGenOption.GenChannelId, false);
                    }
                    arbWfmGenOptions[i] = arbWfmGenOption;
                    optionsChanged = true;
                }
                auxOut = channelActive && (auxOut || arbWfmGenOption.AuxOut);
                channel = auxOut && arbWfmGenOption.AuxOut ? arbWfmGenOption.GenChannelId : channel;
            }

            //#region 外触发开关
            AWG_TRG_OUT_ENABLE_CTRL(channel, auxOut && channelActive);
            if (optionsChanged || isSendTrigger)
            {
                isSendTrigger = false;
                ConfigAWGTrigger();
                AWG_CH_RST();
            }

            AWG_HD_Data_Send_Locked = false;
        }
        internal static void PowerOn()
        {
            HdIO.WriteReg(PcieBdReg.W.awg_AwgPowerEn, 0x01);
            //多清几次保护状态
            for (int i = 0; i < 5; i++)
            {
                Thread.Sleep(5);
                ClearAWGProtect(ChannelId.AWG1);
                Thread.Sleep(5);
                ClearAWGProtect(ChannelId.AWG2);
            }
        }

