        internal static void AwgPoweOnAndDACConfig()
        {
            PowerOff();
            PowerOn();
            Thread.Sleep(300);
            ClearTiAdcCaliLog();
            DAC9122_Config_Sequence();
        }
        internal static void PowerOff()
        {
            HdIO.WriteReg(PcieBdReg.W.awg_AwgPowerEn, 0x00);
        }
        private static void ConfigAWGTrigger()
        {
            foreach (var item in Hd.UIMessage!.ArbWfmGen!)
            {
                ushort writeDate = 0;
                if (item.Mode == WfmGenMode.Modulation)
                {
                    writeDate = 0;
                }
                else if (item.WfmGenTrigerSource == TriggerSource.Outside)
                {
                    if (item.AuxIn)
                    {
                        switch (item.AuxInPolarity)
                        {
                            default:
                            case AwgTrigPolarity.Rise:
                                writeDate = 0x1;
                                break;
                            case AwgTrigPolarity.Fall:
                                writeDate = 0x2;
                                break;
                        }
                    }
                }
                else if (item.WfmGenTrigerSource == TriggerSource.Manual)
                {
                    writeDate = 3;
                }
                else
                { // inside
                    writeDate = 0;
                }
                ushort tritype = item.GenChannelId == ChannelId.AWG1 ? AWG1_TRI_TYPE : AWG2_TRI_TYPE;
                WriteAwgBySpi(tritype, writeDate);
            }
        }
        private static void ClearAWGProtect(ChannelId channel)
        {
            switch (channel)
            {

                case ChannelId.AWG1:
                    WriteAwgBySpi(AWG1_CLEAR_PROTECT, 0x01);
                    break;
                case ChannelId.AWG2:
                    WriteAwgBySpi(AWG2_CLEAR_PROTECT, 0x01);
                    break;
                case ChannelId.AWG3:
                    break;
                case ChannelId.AWG4:
                    break;

                default:
                    break;
            }
        }
        private static void ConfigAWG(ChannelId channel, ArbWfmGenOptions arbWfmGenOptions)
        {
            Int64 freqBaseBySweep = arbWfmGenOptions.Frequency;

            #region 基本波形
            _WfmGenCalFocusCh = channel;
            CalibSetAMP(0);
            CalibWfmOffset(0);
            // <Remark>作者：彭博 创建日期：2023/12/1 11:28:00 创建原因：添加只选择波形时才发生波形的功能 </Remark>
            if (arbWfmGenOptions.IsSendWaveType)
            {
                Thread.Sleep(3);//等待稳定
                AWG_BasicWaveType(channel, ArbWfmType.DC, false);
                Thread.Sleep(3);//等待稳定
            }
            if (arbWfmGenOptions.Mode == WfmGenMode.Sweep)
            {
                freqBaseBySweep = (arbWfmGenOptions.SweepFreqStartFreq + arbWfmGenOptions.SweepFreqEndFreq) / 2;
            }
            /// < Remark > 更改人：彭博 创建日期：2024 / 2 / 2 11:43:00 原因：扫频任意波时，目前没有有逐点输出功能 </ Remark >
            bool enablePointByPoint = arbWfmGenOptions.EnablePointByPoint && arbWfmGenOptions.Mode != WfmGenMode.Sweep && arbWfmGenOptions.WfmType == ArbWfmType.Arbitrary;

            AWG_Freq_CTRL(channel, freqBaseBySweep, enablePointByPoint, out double freqBase);
            /// < Remark > 更改人：彭博 创建日期：2024 / 1 / 15 11:43:00 原因：上升沿会影响脉冲波脉宽 </ Remark >
            AWG_Phase_Duty_CTRL(channel, arbWfmGenOptions.WfmType, arbWfmGenOptions.Phase, GetPulseDuty(arbWfmGenOptions), freqBase
                , arbWfmGenOptions.PulseRiseTime, arbWfmGenOptions.PulseFallTime);

            AWG_Mode_CTRL(channel, arbWfmGenOptions.Mode, arbWfmGenOptions.ModMethod);
            // <Remark>作者：彭博 创建日期：2023/12/1 11:28:00 创建原因：添加只选择波形时才发生波形的功能 </Remark>
            if (arbWfmGenOptions.IsSendWaveType)
            {
                AWG_BasicWaveType(channel, arbWfmGenOptions.WfmType, enablePointByPoint);
            }
            var setamp = arbWfmGenOptions.Amplitude;
            if (arbWfmGenOptions.WfmType == ArbWfmType.DC)
            {
                CalibSetAMP(0);
                if ((arbWfmGenOptions.Offset < 600) && (arbWfmGenOptions.Offset > -600))//jcg
                {
                    ArbWfmGenAttDic[channel] = 2;

                }
                else
                {
                    ArbWfmGenAttDic[channel] = 0;
                }
                CalibATT(ArbWfmGenAttDic[channel]);
                CalibWfmOffset(arbWfmGenOptions.Offset / 1000.0 / 2);
                //CalibATT(0);
                //CalibWfmOffset(arbWfmGenOptions.Offset / 1000.0 / 2);
            }
            else
            {
                WfmGenGetATT(channel, setamp / 1000.0, arbWfmGenOptions.Offset / 1000.0);
                AWG_Offset_Amplitue(channel, arbWfmGenOptions.Offset, setamp, arbWfmGenOptions.Impedance);
            }
            #endregion  基本波形

            #region 调制
            if (arbWfmGenOptions.Mode == WfmGenMode.Modulation)
            {
                AWG_Modulation_Config(channel, arbWfmGenOptions.ModMethod, arbWfmGenOptions.ModFreq, arbWfmGenOptions.Frequency
                    , arbWfmGenOptions.FreqBias, arbWfmGenOptions.AmpDepth, arbWfmGenOptions.PhaseBias, arbWfmGenOptions.ModWfmType, arbWfmGenOptions.RampType);
            }
            #endregion 调制

            #region 扫频
            if (arbWfmGenOptions.Mode == WfmGenMode.Sweep)
            {
                var modMethod = WfmModMethod.FM;

                var freqBias = arbWfmGenOptions.SweepFreqEndFreq - freqBaseBySweep;
                var modWfmType = arbWfmGenOptions.SweepFreqType == SweepType.Linear ? ArbWfmType.Ramp : ArbWfmType.ExpRise;
                var modFreq = 1000_000_000_000.0 / arbWfmGenOptions.SweepFreqTime;
                // < Remark > 更改人：彭博 创建日期：2024 / 1 / 14 14:37:00 原因：扫频时需要确认频率上升扫频还是下降扫频 </ Remark >
                var wfmRampType = freqBias >= 0 ? WfmRampType.Rise : WfmRampType.Fall;

                #region 赋值调制波形数据
                // < Remark > 更改人：彭博 创建日期：2024 / 1 / 14 14:37:00 原因：当对数扫频时需要获取波形数据 </ Remark >
                if (arbWfmGenOptions.SweepFreqType == SweepType.Logarithmic)
                {
                    List<int> data = new List<int>();
                    foreach (var item in log_wave)
                    {
                        data.Add(item);
                    }
                    arbWfmGenOptions.ModArbWfmData = CreatSweepLog(arbWfmGenOptions.SweepFreqStartFreq, arbWfmGenOptions.SweepFreqEndFreq, moduDataDeep).ToList();
                }
                #endregion
                AWG_Modulation_Config(channel, modMethod, modFreq, freqBaseBySweep
                   , Math.Abs(freqBias), arbWfmGenOptions.AmpDepth, arbWfmGenOptions.PhaseBias, modWfmType, wfmRampType);

                //AWG_Sweep_Config(channel, arbWfmGenOptions.SweepFreqStartFreq, arbWfmGenOptions.SweepFreqEndFreq,
                //     arbWfmGenOptions.SweepFreqType, arbWfmGenOptions.SweepFreqTime, arbWfmGenOptions.Frequency);
            }
            #endregion 扫频

            //2024/4/15 解决AWG上电后，未发送校准数据的问题
            AWG_CH_CTRL(channel, arbWfmGenOptions.Active);
        }

        /// <summary>
        /// 获取脉宽
        /// </summary>
        /// <param name="arbWfmGenOptions"></param>
        /// <returns></returns>
        /// < Remark > 更改人：彭博 创建日期：2024 / 1 / 15 11:43:00 原因：上升沿会影响脉冲波脉宽 </ Remark >
        public static Int32 GetPulseDuty(ArbWfmGenOptions arbWfmGenOptions)
        {
            double pulseRiseTime = arbWfmGenOptions.WfmType == ArbWfmType.Pulse ? arbWfmGenOptions.PulseRiseTime : 5000;
            double pulseFallTime = arbWfmGenOptions.WfmType == ArbWfmType.Pulse ? arbWfmGenOptions.PulseFallTime : 5000;
            double dt = pulseRiseTime - pulseFallTime;
            Int32 ret = dt > 0 ? 5000 : -5000;//初始5ns的偏差
            ret = dt == 0 ? 0 : ret; //若上升沿和下降沿的值一致，取消偏差
            return (Int32)((arbWfmGenOptions.Duty - (dt + ret) * 1e-5 * 0.625 * arbWfmGenOptions.Frequency / 1e+9));
        }
