        private static void SendWaveTrigger(ChannelId id)
        {
            if (!Hd.CurrProduct!.HardwareConfig!.bExistAWGModule)
                return;
            if (_CalStatus != WfmGenCalStatus.OFF)
            {
                return;
            }
            ArbWfmGenOptions? arbWfmGenOptions = null;
            UInt16 cmd = 0;

            if (id == ChannelId.AWG1)
            {
                arbWfmGenOptions = Hd.UIMessage!.ArbWfmGen![0];//通道1选择

                cmd = AWG1_TIGRRER_ENABLE;
            }
            else if (id == ChannelId.AWG2)
            {
                arbWfmGenOptions = Hd.UIMessage!.ArbWfmGen!.Length > 1 ? Hd.UIMessage!.ArbWfmGen![1] : null;//通道2选择
                cmd = AWG2_TIGRRER_ENABLE;
            }

            if (arbWfmGenOptions == null || !arbWfmGenOptions.Active || arbWfmGenOptions.WfmGenTrigerSource != TriggerSource.Manual)
            {
                return;
            }
            WriteAwgBySpi(AWG_TIGRRER_DO_REG, 0);
            WriteAwgBySpi(AWG_TIGRRER_DO_REG, cmd);
            WriteAwgBySpi(AWG_TIGRRER_DO_REG, 0);
            // < Remark > 更改人：彭博 创建日期：2024 / 1 / 22 15:41:00 原因：当手动触发时，需要发送一次波形 </ Remark >
            isSendTrigger = true;
            Config();
        }
