        internal static void SendWaveTrigger1()
        {
            SendWaveTrigger(ChannelId.AWG1);
        }
        internal static void SendWaveTrigger2()
        {
            SendWaveTrigger(ChannelId.AWG2);
        }
        public static bool Normalization(ref double[] data)
        {
            return Normalization(ref data, data.Length);
        }
        public static bool Normalization(ref double[] data, int length)
        {
            if (length == 0)
            {
                return false;
            }
            var dataLst = data.ToList();
            var max = dataLst.Max();
            var min = dataLst.Min();
            var absMax = Math.Abs(max) > Math.Abs(min) ? Math.Abs(max) : Math.Abs(min);

            //<Remark>更改人：彭博 创建日期：2023/12/13 16:35:00  原因：一些波形数据仅有正或负，导致波形偏移 </Remark>
            if (min > 0 || max == 0)
            {
                for (int i = 0; i < data.Length; i++)
                {
                    //data[i] = data[i] / absMax / 2 + 0.5;
                    data[i] = (data[i] / absMax + 0.5) * 2;
                }
            }
            else if (max <= 0 || min == 0)
            {
                for (int i = 0; i < data.Length; i++)
                {
                    //data[i] = data[i] / absMax / 2 - 0.5;
                    data[i] = (data[i] / absMax - 0.5) * 2;
                }
            }
            else
            {
                for (int i = 0; i < data.Length; i++)
                {
                    data[i] = data[i] / absMax;
                }
            }

            return true;
        }
