        private static void AWG_Freq_CTRL(ChannelId channel, double frequency, bool enablePointByPoint, out double freqBase)
        {
            freqBase = frequency * Math.Pow(2.0, 47) / 312_500_000.0 / 1000_000.0; //计算频率
            if (enablePointByPoint)
            {
                //<Remark>更改人：彭博 创建日期：2024/2/20 13:23:00  原因：逐点输出，应按波类型的样点数，进行输出 </Remark>
                var data = channel == ChannelId.AWG1 ? Hd.UIMessage!.ArbWfmGen![0].ArbWfmData : Hd.UIMessage!.ArbWfmGen![1].ArbWfmData;
                if (data != null)
                {
                    freqBase = freqBase / (data.Count);
                }
            }
            _CalFreq = (Int64)frequency;
            if (channel == ChannelId.AWG1)
            {
                WriteAwgBySpi(AWG1_SIGNAL_PHASE_INC_0, (UInt16)(((UInt64)freqBase) & 0xff));
                WriteAwgBySpi(AWG1_SIGNAL_PHASE_INC_8, (UInt16)(((UInt64)freqBase) >> 8 & 0xff));
                WriteAwgBySpi(AWG1_SIGNAL_PHASE_INC_16, (UInt16)(((UInt64)freqBase) >> 16 & 0xff));
                WriteAwgBySpi(AWG1_SIGNAL_PHASE_INC_24, (UInt16)(((UInt64)freqBase) >> 24 & 0xff));
                WriteAwgBySpi(AWG1_SIGNAL_PHASE_INC_32, (UInt16)(((UInt64)freqBase) >> 32 & 0xff));
                WriteAwgBySpi(AWG1_SIGNAL_PHASE_INC_40, (UInt16)(((UInt64)freqBase) >> 40 & 0xff));
                Debug.WriteLine("======================FREQ========================");
                Debug.WriteLine($"AWG1_CNT_FREQ：{frequency / 1000_000_000} KHz  (REG:{freqBase})");
                //Debug.WriteLine("==================================================");
            }
            else if (channel == ChannelId.AWG2)
            {
                WriteAwgBySpi(AWG2_SIGNAL_PHASE_INC_0, (UInt16)(((UInt64)freqBase) & 0xff));
                WriteAwgBySpi(AWG2_SIGNAL_PHASE_INC_8, (UInt16)(((UInt64)freqBase) >> 8 & 0xff));
                WriteAwgBySpi(AWG2_SIGNAL_PHASE_INC_16, (UInt16)(((UInt64)freqBase) >> 16 & 0xff));
                WriteAwgBySpi(AWG2_SIGNAL_PHASE_INC_24, (UInt16)(((UInt64)freqBase) >> 24 & 0xff));
                WriteAwgBySpi(AWG2_SIGNAL_PHASE_INC_32, (UInt16)(((UInt64)freqBase) >> 32 & 0xff));
                WriteAwgBySpi(AWG2_SIGNAL_PHASE_INC_40, (UInt16)(((UInt64)freqBase) >> 40 & 0xff));
                Debug.WriteLine($"AWG2_CNT_FREQ：{frequency / 1000_000_000} KHz  (REG:{freqBase})");
            }
        }

