        private static void AWG_Phase_Duty_CTRL(ChannelId channelId, ArbWfmType arbWfmType, double phase, double dutySet, double freqBase,
            Int64 pulseRiseTime, Int64 pulseFallTime)
        {
            var phaseAddr = AWG2_PHASE_OFFSET_0;
            var dutyAddr = AWG2_PULSE_DUTY_0;

            var rampRiseAddr = AWG2_TRI_RISE_0;
            var rampFallAddr = AWG2_TRI_FALL_0;

            var rampRiseShift = AWG2_TRI_RISE_SHIFT;
            var rampFallShift = AWG2_TRI_FALL_SHIFT;
            phase = phase / 360 / 100 * Math.Pow(2, 32);
            double duty = 0;

            //<Remark>更改人：彭博 创建日期：2023/11/24 16:44:00  原因：技术手册改动，将锯齿波和三角波合为斜波 </Remark>
            //if (arbWfmType == ArbWfmType.Square || arbWfmType == ArbWfmType.Triangular)
            //<Remark>更改人：彭博 创建日期：2023/12/4 10:17:00  原因：对方波不做限制，按脉冲波的方式进行设置</Remark>
            //if (arbWfmType == ArbWfmType.Square)
            //{
            //    dutySet = 5000;
            //}
            if (arbWfmType == ArbWfmType.Pulse || arbWfmType == ArbWfmType.Square)
            {
                //脉冲波 反过来 23.11.20
                duty = (100.0 - dutySet / 100.0) * Math.Pow(2.0, 47) / 100; //计算脉宽
                                                                            //duty = (dutySet / 100.0) * Math.Pow(2.0, 47) / 100; //计算脉宽
            }
            else
            {
                //三角波 反过来
                duty = (100.0 - dutySet / 100.0) * Math.Pow(2.0, 47) / 100; //计算脉宽
                                                                            //duty = (dutySet / 100.0) * Math.Pow(2.0, 47) / 100; //计算脉宽
            }


            switch (channelId)
            {
                case ChannelId.AWG1:
                    phaseAddr = AWG1_PHASE_OFFSET_0;
                    // <Remark>更改人：彭博 创建日期：2024/1/14 14:37:00 原因：当通道1未选择斜波、方波、脉冲波时，会使用通道2的寄存器地址下发 </Remark>
                    dutyAddr = AWG1_PULSE_DUTY_0;
                    //if (arbWfmType == ArbWfmType.Triangular || arbWfmType == ArbWfmType.Ramp)
                    //<Remark>更改人：彭博 创建日期：2023/11/24 16:44:00  原因：技术手册改动，将锯齿波和三角波合为斜波 </Remark>
                    if (arbWfmType == ArbWfmType.Ramp)
                    {
                        dutyAddr = AWG1_TRI_DUTY_0;
                    }
                    else if (arbWfmType == ArbWfmType.Square || arbWfmType == ArbWfmType.Pulse)
                    {
                        dutyAddr = AWG1_PULSE_DUTY_0;
                    }

                    rampRiseAddr = AWG1_TRI_RISE_0;
                    rampFallAddr = AWG1_TRI_FALL_0;
                    rampRiseShift = AWG1_TRI_RISE_SHIFT;
                    rampFallShift = AWG1_TRI_FALL_SHIFT;
                    break;
                default:
                case ChannelId.AWG2:
                    //<Remark>更改人：彭博 创建日期：2023/11/24 16:44:00  原因：技术手册改动，将锯齿波和三角波合为斜波 </Remark>
                    //if (arbWfmType == ArbWfmType.Triangular || arbWfmType == ArbWfmType.Ramp)
                    if (arbWfmType == ArbWfmType.Ramp)
                    {
                        dutyAddr = AWG2_TRI_DUTY_0;
                    }
                    else if (arbWfmType == ArbWfmType.Square || arbWfmType == ArbWfmType.Pulse)
                    {
                        dutyAddr = AWG2_PULSE_DUTY_0;
                    }
                    break;
                    //case ChannelId.AWG3:
                    //	break;
                    //case ChannelId.AWG4:
                    //	break;
            }
            for (int dutyIndex = 0; dutyIndex < 6; dutyIndex++)
            {
                WriteAwgBySpi((UInt16)(dutyAddr + dutyIndex), (UInt16)(((UInt64)duty) >> (dutyIndex * 8) & 0xff));
            }

            for (int phaseIndex = 0; phaseIndex < 4; phaseIndex++)
            {
                WriteAwgBySpi((UInt16)(phaseAddr + phaseIndex), (UInt16)(((UInt64)phase) >> (phaseIndex * 8) & 0xff));
            }

            #region 斜波
            //<Remark>更改人：彭博 创建日期：2023/11/24 16:44:00  原因：技术手册改动，将锯齿波和三角波合为斜波 </Remark>
            //if (arbWfmType == ArbWfmType.Ramp || arbWfmType == ArbWfmType.Triangular)
            if (arbWfmType == ArbWfmType.Ramp)
            {
                //<Remark>更改人：彭博 创建日期：2024/1/22 10:25:00  原因：当对称性在0.5%时，波形异常，int丢失了精度，需改为long </Remark>
                long ramp_rise_tem = (long)(100 * Math.Pow(2.0, 24) / (100 - dutySet * 1.0 / 100) / 1.002);//上升，整形 
                long ramp_fall_tem = (long)(100 * Math.Pow(2.0, 24) / (dutySet * 1.0 / 100) / 1.002);//下降，整形 
                                                                                                     //int ramp_rise_tem = (int)(100 * Math.Pow(2.0, 24) / (dutySet / 100) / 1.002);//上升，整形 
                                                                                                     //int ramp_fall_tem = (int)(100 * Math.Pow(2.0, 24) / (100 - dutySet / 100) / 1.002);//下降，整形 

                string valid_ramp_rise_0B_Value = Convert.ToString(ramp_rise_tem, 2);//将计算出来的整形转换为二进制形式
                string valid_ramp_fall_0B_Value = Convert.ToString(ramp_fall_tem, 2);

                string valid_ramp_rise = valid_ramp_rise_0B_Value.TrimStart();//消除开头的非零位，从第一位不是0的位开始
                                                                              //string valid_ramp_fall = ramp_fall_string.TrimStart();
                string valid_ramp_fall = valid_ramp_fall_0B_Value.TrimStart();//消除开头的非零位，从第一位不是0的位开始    

                //上升
                string str1_rise_high = valid_ramp_rise.Substring(0, 8);//取高八位
                UInt16 ramp_rise_high = (Convert.ToUInt16(str1_rise_high, 2));  //上升沿计算将字符串型转换为二进制           
                string str1_rise_mid = valid_ramp_rise.Substring(8, 8);//取中八位
                UInt16 ramp_rise_mid = (Convert.ToUInt16(str1_rise_mid, 2));
                string str1_rise_low = valid_ramp_rise.Substring(16, 8);//取低八位
                UInt16 ramp_rise_low = Convert.ToUInt16(str1_rise_low, 2);
                string str1_rise_lastString = valid_ramp_rise.Substring(24).TrimStart();//取最后
                UInt64 str1_rise_last = (ulong)str1_rise_lastString.Length;
                //下降
                string str1_fall_high = valid_ramp_fall.Substring(0, 8);//取高八位
                UInt16 ramp_fall_high = (Convert.ToUInt16(str1_fall_high, 2));  //上升沿计算将字符串型转换为二进制           
                string str1_fall_mid = valid_ramp_fall.Substring(8, 8);//取中八位
                UInt16 ramp_fall_mid = (Convert.ToUInt16(str1_fall_mid, 2));
                string str1_fall_low = valid_ramp_fall.Substring(16, 8);//取低八位
                UInt16 ramp_fall_low = Convert.ToUInt16(str1_fall_low, 2);
                string str1_fall_lastString = (valid_ramp_fall.Substring(24)).TrimStart();//取最后
                UInt64 str1_fall_last = (ulong)str1_fall_lastString.Length;

                WriteAwgBySpi(rampRiseAddr, (UInt16)((ramp_rise_low) & 0xff));  //三角波上升沿计算
                WriteAwgBySpi((UInt16)(rampRiseAddr + 1), (UInt16)((ramp_rise_mid) & 0xff));
                WriteAwgBySpi((UInt16)(rampRiseAddr + 2), (UInt16)((ramp_rise_high) & 0xff));

                WriteAwgBySpi(rampFallAddr, (UInt16)((ramp_fall_low) & 0xff));  //三角波下降沿计算
                WriteAwgBySpi((UInt16)(rampFallAddr + 1), (UInt16)((ramp_fall_mid) & 0xff));
                WriteAwgBySpi((UInt16)(rampFallAddr + 2), (UInt16)((ramp_fall_high) & 0xff));

                WriteAwgBySpi(rampRiseShift, (UInt16)((str1_rise_last) & 0xff));
                WriteAwgBySpi(rampFallShift, (UInt16)((str1_fall_last) & 0xff));
            }

            #endregion 三角波

            #region 方波脉冲
            else if (arbWfmType == ArbWfmType.Square || arbWfmType == ArbWfmType.Pulse)
            {
                try
                {
                    var riseAddr = channelId == ChannelId.AWG1 ? AWG1_PULSE_REDGE_OFFSET_0 : AWG2_PULSE_REDGE_OFFSET_0;
                    var fallAddr = channelId == ChannelId.AWG1 ? AWG1_PULSE_FEDGE_OFFSET_0 : AWG2_PULSE_FEDGE_OFFSET_0;
                    var riseStepAddr = channelId == ChannelId.AWG1 ? AWG1_RSTEP_SHIFT : AWG2_RSTEP_SHIFT;
                    var fallStepAddr = channelId == ChannelId.AWG1 ? AWG1_FSTEP_SHIFT : AWG2_FSTEP_SHIFT;

                    //<Remark>更改人：彭博 创建日期：2023/12/07 16:27:00  原因：用于校准上升时间和下降时间 </Remark>
                    var pulseRiseTimeNs = pulseRiseTime / 1000d;
                    var pulseFallTimeNs = pulseFallTime / 1000d;

                    //var pulseRiseTimeNs = (pulseRiseTime - RiseTimeMapSingle.GetInstance().GetOffsetCount(pulseRiseTime)) / 1000d;
                    //var pulseFallTimeNs = (pulseFallTime - RiseTimeMapSingle.GetInstance().GetOffsetCount(pulseFallTime)) / 1000d;

                    double sample = 3.2;
                    double riseTime = 2;//方波 2ns
                    int nRise = 0;
                    int nFall = 0;
                    double redge = 65535 * sample / (freqBase * riseTime);
                    double fedge = redge;
                    if (arbWfmType == ArbWfmType.Pulse)
                    {
                        redge = 65535 * sample / (freqBase * GetPulseTime(pulseRiseTimeNs)) / 1.25;
                        fedge = 65535 * sample / (freqBase * GetPulseTime(pulseFallTimeNs)) / 1.25;
                    }
                    var max = (double)Math.Pow(2, 24);
                    var min = (double)Math.Pow(2, 23);
                    while (!(redge >= min && redge <= max))
                    {

                        if (redge < min)
                        {
                            redge *= 2;
                            nRise++;
                        }
                        else if (redge > max)
                        {
                            redge /= 2;
                            nRise--;
                        }

                    }

                    if (redge > max || nRise < 0)
                    {
                        //error
                        return;
                    }
                    while (!(fedge >= min && fedge <= max))
                    {
                        if (fedge < min)
                        {
                            fedge *= 2;
                            nFall++;
                        }
                        else if (fedge > max)
                        {
                            fedge /= 2;
                            nFall--;
                        }
                    }
                    if (fedge > max || nFall < 0)
                    {
                        //error
                        return;
                    }
                    //fpga 上下好像反了 23.9版本解决
                    for (int i = 0; i < 3; i++)
                    {
                        WriteAwgBySpi((ushort)(riseAddr + i), (UInt16)((((UInt64)redge) >> (i * 8)) & 0xff));
                        WriteAwgBySpi((ushort)(fallAddr + i), (UInt16)((((UInt64)fedge) >> (i * 8)) & 0xff));
                    }
                    WriteAwgBySpi((ushort)riseStepAddr, (UInt16)nRise);
                    WriteAwgBySpi((ushort)fallStepAddr, (UInt16)nFall);
                }
                catch (Exception e)
                {

                }
            }
            #endregion 方波脉冲
        }

        private static double GetPulseTime(double pulseTime)
        {
            if (pulseTime < 6)
            {
                pulseTime -= 3;
            }
            else if (pulseTime < 7)
            {
                pulseTime -= 2.5;
            }
            else if (pulseTime < 8)
            {
                pulseTime -= 1;
            }
            else if (pulseTime >= 11 && pulseTime < 100)
            {
                pulseTime += 0.8;
            }
            return pulseTime;
        }


        public static void AWG_Mode_CTRL(ChannelId channelId, WfmGenMode mode, WfmModMethod modMethod)
        {
            var regAddr = AWG2_WORK_MODE;
            switch (channelId)
            {
                case ChannelId.AWG1:
                    regAddr = AWG1_WORK_MODE;
                    break;
                default:
                case ChannelId.AWG2:
                    break;
                    //case ChannelId.AWG3:
                    //	break;
                    //case ChannelId.AWG4:
                    //	break;
            }
            switch (mode)
            {
                default:
                case WfmGenMode.Continuous:
                    WriteAwgBySpi(regAddr, (ushort)Convert.ToInt32(0));
                    break;
                case WfmGenMode.Modulation:
                    switch (modMethod)
                    {
                        case WfmModMethod.FM:
                            WriteAwgBySpi(regAddr, 2);
                            break;
                        case WfmModMethod.AM:
                            WriteAwgBySpi(regAddr, 1);
                            break;
                        case WfmModMethod.PM:
                            WriteAwgBySpi(regAddr, 3);
                            break;
                        case WfmModMethod.FSK:
                            WriteAwgBySpi(regAddr, 5);
                            break;
                        default:
                            break;
                    }

                    break;
                case WfmGenMode.Sweep:
                    WriteAwgBySpi(regAddr, 2);
                    break;
            }

        }

        private static void AWG_Modulation_Config(ChannelId channelId, WfmModMethod modMethod, double modFreq
            , double basicFreq, double freqBias, double ampDepth, double phaseBias, ArbWfmType modWaveType, WfmRampType rampType)
        {
            var regModula = AWG2_MODULA_INC_0;
            var degreeReg = AWG2_MODULA_DEGREE_0;
            var modWaveReg = AWG2_MODULA_WAVE_SEL;
            var dataSetReg = AWG2_DATA_SET_MOD;
            switch (channelId)
            {
                case ChannelId.AWG1:
                    regModula = AWG1_MODULA_INC_0;
                    degreeReg = AWG1_MODULA_DEGREE_0;
                    modWaveReg = AWG1_MODULA_WAVE_SEL;
                    dataSetReg = AWG1_DATA_SET_MOD;
                    break;
                default:
                case ChannelId.AWG2:
                    break;
                    //case ChannelId.AWG3:
                    //	break;
                    //case ChannelId.AWG4:
                    //	break;
            }

            modFreq = modFreq / 1000_000.0;
            modFreq *= Math.Pow(2.0, 47) / 312_500_000; //计算频率
                                                        //调制频率
            for (int modRegIndex = 0; modRegIndex < 6; modRegIndex++)
            {
                WriteAwgBySpi((UInt16)(regModula + modRegIndex), (UInt16)(((UInt64)modFreq) >> (8 * modRegIndex) & 0xff));
            }

            if (modMethod == WfmModMethod.FM)
            {
                freqBias = freqBias / 1000_000.0;
                if (basicFreq - freqBias < 0)
                {
                    freqBias = basicFreq / 1000_000.0;
                }
                freqBias *= Math.Pow(2.0, 47) / 312_500_000;
                //调制度,频偏
                for (int modulaIndex = 0; modulaIndex < 6; modulaIndex++)
                {
                    WriteAwgBySpi((UInt16)(degreeReg + modulaIndex), (UInt16)(((UInt64)freqBias) >> (8 * modulaIndex) & 0xff));
                }
            }
            else if (modMethod == WfmModMethod.AM)
            {
                ampDepth = ampDepth / 100.0 * Math.Pow(2.0, 47);
                //调制度,调幅  0-120%
                for (int modulaIndex = 0; modulaIndex < 6; modulaIndex++)
                {
                    WriteAwgBySpi((UInt16)(degreeReg + modulaIndex), (UInt16)(((UInt64)ampDepth) >> (8 * modulaIndex) & 0xff));
                }
            }
            else if (modMethod == WfmModMethod.PM)
            {
                phaseBias = phaseBias / 360.0 / 100.0 * Math.Pow(2.0, 48);
                //调制度 
                for (int modulaIndex = 0; modulaIndex < 6; modulaIndex++)
                {
                    WriteAwgBySpi((UInt16)(degreeReg + modulaIndex), (UInt16)(((UInt64)phaseBias) >> (8 * modulaIndex) & 0xff));
                }
            }

            //调制波形

            switch (modWaveType)
            {
                case ArbWfmType.Square:
                    WriteAwgBySpi(modWaveReg, 1);
                    break;
                case ArbWfmType.Ramp:
                    if (rampType == WfmRampType.Rise)
                    {
                        WriteAwgBySpi(modWaveReg, 2);
                    }
                    else
                    {
                        WriteAwgBySpi(modWaveReg, 3);
                    }
                    break;

                case ArbWfmType.Sinusoid:
                    WriteAwgBySpi(modWaveReg, 0);
                    WriteAwgBySpi(WRITE_DATA_SEL, dataSetReg);
                    WriteAwgBySpi(WRITE_DATA_WE, 0x01);
                    SineWave(moduDataDeep);
                    WriteAwgBySpi(WRITE_DATA_WE, 0x00);
                    break;
                case ArbWfmType.Noise:
                default:
                    WriteAwgBySpi(modWaveReg, 0);
                    WriteAwgBySpi(WRITE_DATA_SEL, dataSetReg);
                    WriteAwgBySpi(WRITE_DATA_WE, 0x01);
                    ArbitryModeWave(channelId);//任意波
                    WriteAwgBySpi(WRITE_DATA_WE, 0x00);
                    break;
            }
        }

        private static void AWG_BasicWaveType(ChannelId channelId, ArbWfmType wfmType, bool enablePointByPoint)
        {
            var regSignalAddr = AWG2_SIGNAL_SEL;
            var regAttenAddr = AWG2_CNT_ATTEN;
            var dataSetReg = AWG2_DATA_SET_BASE;
            var dataChangeReg = AWG2_DATA_SET_CHANGE;
            switch (channelId)
            {
                case ChannelId.AWG1:
                    regSignalAddr = AWG1_SIGNAL_SEL;
                    regAttenAddr = AWG1_CNT_ATTEN;
                    dataSetReg = AWG1_DATA_SET_BASE;
                    dataChangeReg = AWG1_DATA_SET_CHANGE;
                    break;
                default:
                case ChannelId.AWG2:
                    break;
                    //case ChannelId.AWG3:
                    //	break;
                    //case ChannelId.AWG4:
                    //	break;
            }

            switch (wfmType)
            {
                case ArbWfmType.Sinusoid: //正弦
                    WriteAwgBySpi(regSignalAddr, 0x00);
                    WriteAwgBySpi(WRITE_DATA_SEL, dataSetReg);
                    WriteAwgBySpi(WRITE_DATA_WE, 0x01);
                    SineWave();
                    WriteAwgBySpi(WRITE_DATA_WE, 0x00);

                    //WriteAwgBySpi(WRITE_DATA_SEL, dataChangeReg);
                    //WriteAwgBySpi(WRITE_DATA_WE, 0x01);
                    //SineWave();
                    //WriteAwgBySpi(WRITE_DATA_WE, 0x00);
                    break;

                case ArbWfmType.Pulse: //脉冲
                case ArbWfmType.Square: //方波
                    WriteAwgBySpi(regSignalAddr, 0x01);
                    break;
                //<Remark>更改人：彭博 创建日期：2023/11/24 16:44:00  原因：技术手册改动，将锯齿波和三角波合为斜波 </Remark>
                case ArbWfmType.Ramp: //斜波
                                      //case ArbWfmType.Triangular: //三角波
                    WriteAwgBySpi(regSignalAddr, 0x05);
                    //WriteAwgBySpi(regAttenAddr, 0x00); //幅度挡位选择
                    break;

                case ArbWfmType.DC:
                    WriteAwgBySpi(regSignalAddr, 0x04);
                    WriteAwgBySpi(WRITE_DATA_SEL, dataSetReg);
                    WriteAwgBySpi(WRITE_DATA_WE, 0x01);

                    break;
                case ArbWfmType.Noise: //噪声
                case ArbWfmType.ExpFall://指数下降
                case ArbWfmType.ExpRise:
                case ArbWfmType.Gaussian://高斯波
                case ArbWfmType.Haversine://半正弦波
                case ArbWfmType.Sinc://sinc波
                case ArbWfmType.Lorentz://Lorentz波形
                case ArbWfmType.ECG://心率波
                case ArbWfmType.Arbitrary:
                    // < Remark > 更改人：彭博 创建日期：2024 / 2 / 28 14:42:00 原因：当任意波波形没有时，默认不发送波形，切换为直流 </ Remark >
                    var data = channelId == ChannelId.AWG1 ? Hd.UIMessage!.ArbWfmGen![0].ArbWfmData : Hd.UIMessage!.ArbWfmGen![1].ArbWfmData;
                    if (data == null)
                    {
                        break;
                    }
                    if (enablePointByPoint)
                    {
                        ArbPointByPoint(channelId);
                        WriteAwgBySpi(regSignalAddr, 0x03);
                        //if (channelId!= ChannelId.AWG2)
                        //{
                        //                      Thread.Sleep(500);
                        //                  }
                    }
                    else
                    {
                        WriteAwgBySpi(regSignalAddr, 0x00);
                        WriteAwgBySpi(WRITE_DATA_SEL, dataSetReg);
                        WriteAwgBySpi(WRITE_DATA_WE, 0x01);
                        ArbitryWave(channelId);//任意波
                        WriteAwgBySpi(WRITE_DATA_WE, 0x00);
                    }

                    //WriteAwgBySpi(WRITE_DATA_SEL, dataChangeReg);
                    //WriteAwgBySpi(WRITE_DATA_WE, 0x01);
                    //ArbitryWave();//任意波
                    //WriteAwgBySpi(WRITE_DATA_WE, 0x00);
                    break;
            }
        }
        public static int[] CreatSweepLog(double StartFre, double EndFre, int mod_len)
        {
            int[] pModulate = new int[mod_len];
            double AMP_CAL_MAX = 32767.0;
            double minFre = StartFre > EndFre ? EndFre : StartFre;
            double maxFre = StartFre > EndFre ? StartFre : EndFre;
            double startx = Math.Log10(minFre);
            double stopx = Math.Log10(maxFre);
            double span = maxFre - minFre;
            double step = (stopx - startx) / (double)(mod_len - 1);
            short modwMin = (short)(0 - (short)((ushort)(AMP_CAL_MAX) / 2 + 1));
            short modwMax = (short)((short)(AMP_CAL_MAX) / 2);
            double tmp;
            double fstep = Math.Pow(10, step);

            if (StartFre <= EndFre)
            {
                tmp = Math.Pow(10, 0);
                for (int i = 0; i < mod_len; i++)
                {
                    double rvaule = (minFre * tmp - minFre) / span * 2 - 1;
                    pModulate[i] = (int)(rvaule * modwMax);
                    tmp *= fstep;
                    // pModulate[i] = ((pow(10,startx + i*step) - minFre)/span * 2 - 1)*modwMax;
                    if (pModulate[i] >= modwMax)
                        pModulate[i] = modwMax;
                    if (pModulate[i] < modwMin)
                        pModulate[i] = modwMin;
                }
            }
            else
            {
                tmp = Math.Pow(10, (mod_len - 1) * step);
                for (int i = 0; i < mod_len; i++)
                {
                    double rvaule = (minFre * tmp - minFre) / span * 2 - 1;
                    pModulate[i] = (int)(rvaule * modwMax);
                    tmp /= fstep;
                    // pModulate[i] = ((pow(10,startx+(mod_len -i-1)*step) - minFre)/span * 2 - 1)*modwMax;
                    if (pModulate[i] > modwMax)
                        pModulate[i] = modwMax;
                    if (pModulate[i] < modwMin)
                        pModulate[i] = modwMin;
                }
            }
            return pModulate;
        }

        public static void AWG_Sweep_Config(ChannelId channelId, double startFreq, double endFreq
            , SweepType sweepType, double sweepFreqTime, double basicFreq)
        {
            var degreeReg = AWG2_MODULA_DEGREE_0;
            var modReg = AWG2_MODULA_INC_0;
            var awgSignPhase = AWG2_SIGNAL_PHASE_INC_0;
            var awgSweepStop = AWG2_FREQ_SWEEP_STOP_0;
            var awgWorkMode = AWG2_WORK_MODE;
            switch (channelId)
            {
                case ChannelId.AWG1:
                    degreeReg = AWG1_MODULA_DEGREE_0;
                    modReg = AWG1_MODULA_INC_0;
                    awgSignPhase = AWG1_SIGNAL_PHASE_INC_0;
                    awgSweepStop = AWG1_FREQ_SWEEP_STOP_0;
                    awgWorkMode = AWG1_WORK_MODE;
                    break;
                default:
                case ChannelId.AWG2:
                    break;
                    //case ChannelId.AWG3:
                    //	break;
                    //case ChannelId.AWG4:
                    //	break;
            }
            #region 频率计算
            double freqSweepStart = startFreq * Math.Pow(2.0, 47) / 312_500_000 / 1000_000.0;
            double freqSweepStop = endFreq * Math.Pow(2.0, 47) / 312_500_000 / 1000_000.0;
            double freqBias = 0;
            var freqBase = (freqSweepStart + freqSweepStop) / 2;
            if (freqSweepStart < freqSweepStop)
            {
                freqBias = (freqSweepStop - freqSweepStart) / 2;
            }
            else
            {
                freqBias = -((freqSweepStop - freqSweepStart) / 2);
            }
            if (basicFreq - freqBias < 0)
            {
                freqBias = basicFreq;
            }
            #endregion 频率计算
            WriteAwgBySpi(awgWorkMode, 0x2);
            //调制度,频偏
            for (UInt16 degreeIndex = 0; degreeIndex < 6; degreeIndex++)
            {
                WriteAwgBySpi((UInt16)(degreeReg + degreeIndex), (UInt16)(((UInt64)freqBias) >> (8 * degreeIndex) & 0xff));
            }

            double sweepFreq = (1.0 / (sweepFreqTime / 1000_000.0));
            sweepFreq *= Math.Pow(2.0, 47) / 312_500_000; //计算频率
                                                          //调制频率  
            for (UInt16 sweepIndex = 0; sweepIndex < 6; sweepIndex++)
            {
                WriteAwgBySpi((UInt16)(modReg + sweepIndex), (UInt16)(((UInt64)sweepFreq) >> (8 * sweepIndex) & 0xff));
            }

            //if (basicFreq - freqBias < 0)
            //{
            //	freqBias = basicFreq / 1000_000.0;
            //}
            //扫频类型
            switch (sweepType)
            {
                case SweepType.Linear:
                    if (line_wave.Length != constDataDeep)
                    {
                        LineWave_Init();
                    }
                    ArbitryWaveSend(line_wave);
                    break;
                default:
                case SweepType.Logarithmic:
                    if (log_wave.Length != constDataDeep)
                    {
                        LogWave_Init();
                    }
                    ArbitryWaveSend(log_wave);
                    break;
            }

            //扫频开始频率
            WriteAwgBySpi(awgSignPhase, (UInt16)(((UInt64)freqSweepStart) & 0xff));
            WriteAwgBySpi(awgSignPhase + 1, (UInt16)(((UInt64)freqSweepStart) >> 8 & 0xff));
            WriteAwgBySpi(awgSignPhase + 2, (UInt16)(((UInt64)freqSweepStart) >> 16 & 0xff));
            WriteAwgBySpi(awgSignPhase + 3, (UInt16)(((UInt64)freqSweepStart) >> 24 & 0xff));
            WriteAwgBySpi(awgSignPhase + 4, (UInt16)(((UInt64)freqSweepStart) >> 32 & 0xff));
            WriteAwgBySpi(awgSignPhase + 5, (UInt16)(((UInt64)freqSweepStart) >> 40 & 0xff));
            //扫频停止频率
            WriteAwgBySpi(awgSweepStop, (UInt16)(((UInt64)freqSweepStop) & 0xff));  //计算频率控制字
            WriteAwgBySpi(awgSweepStop + 1, (UInt16)(((UInt64)freqSweepStop) >> 8 & 0xff));
            WriteAwgBySpi(awgSweepStop + 2, (UInt16)(((UInt64)freqSweepStop) >> 16 & 0xff));
            WriteAwgBySpi(awgSweepStop + 3, (UInt16)(((UInt64)freqSweepStop) >> 24 & 0xff));
            WriteAwgBySpi(awgSweepStop + 4, (UInt16)(((UInt64)freqSweepStop) >> 32 & 0xff));
            WriteAwgBySpi(awgSweepStop + 5, (UInt16)(((UInt64)freqSweepStop) >> 40 & 0xff));

        }

        public static void ArbitryWaveSend(UInt16[] buffer, int maxLength = constDataDeep)
        {
            for (int i = 0; i < buffer.Length; i++)
            {
                if (i >= maxLength)
                {
                    break;
                }
                WriteAwgBySpi(SHARE_FPGA_CONFIG_HDATA_L, (UInt16)(buffer[i] & 0xff));
                WriteAwgBySpi(SHARE_FPGA_CONFIG_HDATA_H, (UInt16)(buffer[i] >> 8 & 0xff));
            }
        }
