        /// <summary>
        /// 配置9122DAC
        /// </summary>
        public static bool SetCh9122DAC()
        {
            UInt16[] DACconfig =
            {
                0x0020,    0x0000,
                0x1048,    0x1600,    0x1704,    0x0b00,    0x0a00,
                0x0c01,    0x0d01,    /*0x0e01,*/    0x1be0,
                0x1c01,    0x1d01,    0x1e01,
                0x44ff,    0x4503,    0x40ff,    0x4103,

                //0x1803,    0x1800,    0x1803,    0x1800,   0x1803,    0x1800,
            };
            //UInt32 addr = AD9122_CONFIG_DATA_0;
            UInt32 value = (UInt32)0xff00;
            WriteAwgBySpi(AD9122_CONFIG_DATA_0, (UInt16)(((UInt64)value) & 0xff));
            WriteAwgBySpi(AD9122_CONFIG_DATA_8, (UInt16)(((UInt64)value) >> 8 & 0xff));
            Thread.Sleep(1000);
            char readv;
            //FpgaReadDouble(CONFIG_AD9122_READ, &readv, 1);
            //fprintf(stderr, "9122 version %x\r\n", readv);
            int count = 0;
            for (UInt32 i = 0; i < DACconfig.Length; i++)
            {
                WriteAwgBySpi(AD9122_CONFIG_DATA_0, (UInt16)(((UInt64)DACconfig[i]) & 0xff));
                WriteAwgBySpi(AD9122_CONFIG_DATA_8, (UInt16)(((UInt64)DACconfig[i]) >> 8 & 0xff));
                bool status = true;
                count = 0;
                while (status && count < 5)
                {
                    HdIO.Sleep(500);
                    WriteAwgBySpi(AD9122_CONFIG_DATA_0, (UInt16)((((UInt64)DACconfig[i]) & 0xff)));
                    WriteAwgBySpi(AD9122_CONFIG_DATA_8, (UInt16)((((UInt64)DACconfig[i]) >> 8 & 0xff) | 0x80));
                    uint reslut = ReadAwgRegBySpi(0xFC, DACconfig[i]);
                    status = (reslut != (UInt32)(((UInt64)DACconfig[i]) & 0xff));
                    count++;
                    if (count >= 5)
                    {
                        Hd.SysLogger?.Invoke($"AWG：{DACconfig[i]}-{reslut}", "Debug");
                    }
                }
                if (0x0020 == DACconfig[i])
                {
                    HdIO.Sleep(1000);
                }
                else if (0x0000 == DACconfig[i])
                {
                    HdIO.Sleep(1000);
                }
                else
                {
                    HdIO.Sleep(10);
                }
            }
            ResetDACFIFO();

            return true;
        }

        /// <summary>
        /// 复位DAC
        /// </summary>
        public static void ResetDACFIFO()
        {
            UInt16[] DACconfig =
            {
                0x1803,    0x1800,    0x1803,    0x1800,   0x1803,    0x1800,
            };
            for (UInt32 i = 0; i < DACconfig.Length; i++)
            {
                WriteAwgBySpi(AD9122_CONFIG_DATA_0, (UInt16)(((UInt64)DACconfig[i]) & 0xff));
                WriteAwgBySpi(AD9122_CONFIG_DATA_8, (UInt16)(((UInt64)DACconfig[i]) >> 8 & 0xff));
                HdIO.Sleep(10);
            }
        }

        public static void WriteDACSpi(UInt16 addr, UInt16 data)
        {
            WriteAwgBySpi(AD9122_DATA, data);
            WriteAwgBySpi(AD9122_ADDR, addr);
            Thread.Sleep(1);
            WriteLog($"Write addr:0x{Convert.ToString(addr, 16)}，data:0x{Convert.ToString(data, 16)}");
        }

        public static UInt32 ReadDACSpi(UInt16 addr)
        {
            WriteAwgBySpi(AD9122_DATA, 0x00);
            WriteAwgBySpi(AD9122_ADDR, (UInt16)(addr | 0x80));
            UInt32 data = ReadAwgRegBySpi(0xFC);
            Thread.Sleep(1);
            WriteLog($"Read addr:0x{Convert.ToString(addr, 16)}，data:0x{Convert.ToString(data, 16)}");
            return data;
        }

        public static Boolean DAC9122_Config_Sequence()
        {
            //DAC Hardware Reset,Pull DAC RESET_N PIN HIGH-LOW-HIGH
            HdIO.WriteReg(ProcBdReg.W.reverse_pro_reverse_wr_reg_6, 0U);
            HdIO.WriteReg(ProcBdReg.W.reverse_pro_reverse_wr_reg_6, 1U);
            HdIO.WriteReg(ProcBdReg.W.reverse_pro_reverse_wr_reg_6, 0U);
            Thread.Sleep(1);
            //The Driver Need DATA Before ADDR
            //Sleep DACs

            WriteDACSpi(0x41, 0x80);

            WriteDACSpi(0x45, 0x80);
            //Software Reset

            WriteDACSpi(0x00, 0x20);

            WriteDACSpi(0x00, 0x00);
            //Start PLL

            //WriteAwgBySpi(AD9122_DATA, 0xD9);
            //WriteAwgBySpi(AD9122_ADDR, 0x0D);

            WriteDACSpi(0x0D, 0x01);

            WriteDACSpi(0x0C, 0x01);

            WriteDACSpi(0x0A, 0x00);
            //DCI delay
            //WriteDACSpi(0x16, 0x00);

            //WriteAwgBySpi(AD9122_DATA, 0x00);
            //WriteAwgBySpi(AD9122_ADDR, 0x16);

            //Verify PLL Locked
            UInt32 pll_status = ReadDACSpi(0x0E);//Don't need,because REFCLK not used

            //Configure Interpolation Filters

            WriteDACSpi(0x1B, 0xE0);

            WriteDACSpi(0x1C, 0x01);//bypass

            WriteDACSpi(0x1D, 0x01);//bypass

            WriteDACSpi(0x1E, 0x01);//bypass
            //Configure NCO


            //Choose Data Rate Mode
            WriteDACSpi(0x03, 0x40);
            WriteDACSpi(0x10, 0x48);
            _InitCount = 0;

            //FIFO Reset
            DAC9122_FIFO_Init();

            DAC9122_FIFO_Monitor();

            //Wake Up DACs and Run
            WriteDACSpi(0x41, 0x03);

            WriteDACSpi(0x40, 0xFF);//FS Adj

            WriteDACSpi(0x45, 0x03);

            WriteDACSpi(0x44, 0xFF);//FS Adj

            #region 读取配置
            ReadDACSpi(0x41);
            ReadDACSpi(0x45);
            ReadDACSpi(0x00);
            ReadDACSpi(0x0D);
            ReadDACSpi(0x0C);
            ReadDACSpi(0x0A);
            ReadDACSpi(0x0E);
            ReadDACSpi(0x1B);
            ReadDACSpi(0x1C);
            ReadDACSpi(0x1E);
            ReadDACSpi(0x17);
            ReadDACSpi(0x18);
            ReadDACSpi(0x19);
            ReadDACSpi(0x10);
            ReadDACSpi(0x40);
            ReadDACSpi(0x44);
            #endregion
            return true;
        }


        public static void DAC9122_FIFO_Init(Boolean status = false, UInt16 commendedValue = 0x04)
        {
            WriteLog($"status:{status}，InitCount:{_InitCount},commendedValue:0x{Convert.ToString(commendedValue, 16)}");
            if (status || _InitCount > 5)
            {
                return;
            }
            _InitCount++;
            //
            UInt32 intr_enble = ReadDACSpi(0x04);

            WriteDACSpi(0x17, commendedValue);//recommended

            WriteDACSpi(0x18, 0x02);


            //Verify FIFO Reset
            UInt16 count = 0;

            while (count < 5)
            {
                UInt32 reset_ack = ReadDACSpi(0x18);

                //FIFO Align ACK
                Boolean reset_status = false;
                reset_status = ((reset_ack >> 1 & 0x03) != (UInt16)(0x03));//EXPECT 0x07 [2:1] = 'b11              
                WriteLog($"0x18 count：{count} reset_ack:0x{Convert.ToString(reset_ack, 16)} reset_status:{status}");
                if (reset_status)
                {
                    break;
                }

                count++;
            }

            //Clear FIFO Request,Enable FIFO Warning INTR
            WriteDACSpi(0x18, 0x00);

            WriteDACSpi(0x04, 0x03);

            UInt16 count_clr = 0;

            while (count_clr < 5)
            {
                UInt32 reset_ack = ReadDACSpi(0x18);//EXPECT 0x00

                //FIFO Align ACK
                Boolean reset_status = false;
                reset_status = ((reset_ack >> 1 & 0x03) != (UInt16)(0x00));//EXPECT 0x00 [2:1] = 'b00
                WriteLog($"0x18 count：{count} reset_ack:0x{Convert.ToString(reset_ack, 16)} reset_status:{reset_status}");
                if (reset_status)
                {
                    break;
                }

                count_clr++;
            }
            count = 0;

            Boolean pointer_status = false;
            Int32 num = 0;
            UInt16 pointer = 0;
            while (count < 5)
            {
                pointer = (UInt16)ReadDACSpi(0x19);
                pointer_status = (pointer != (UInt16)(0x07) || pointer != (UInt16)(0x0F) || pointer != (UInt16)(0x1F));
                WriteLog($"0x19 count：{count}  pointer_status:{pointer_status}pointer:0x{Convert.ToString(pointer, 16)}");
                if (!pointer_status)
                {
                    break;
                }
                //验证每次取数结果是否一致
                switch (pointer)
                {
                    case (UInt16)0x07: num += 1; break;
                    case (UInt16)0x0F: num += 2; break;
                    case (UInt16)0x1F: num += 3; break;
                    default:
                        num += 0;
                        break;
                }
                count++;
            }

            pointer_status = (num != 5 || num != 10 || num != 15) && pointer_status;
            if (pointer_status)
            {
                WriteLog($"0x17 pointer_status:{pointer_status} commendedValue:{commendedValue} pointer:0x{Convert.ToString(pointer, 16)}");
                if (pointer != 0x07 && pointer != 0x0F)
                {
                    int pointercount = 0;
                    switch (pointer)
                    {
                        case 0x00: pointercount = 0; break;
                        case 0x01: pointercount = 1; break;
                        case 0x03: pointercount = 2; break;
                        case 0x07: pointercount = 3; break;
                        case 0x0F: pointercount = 4; break;
                        case 0x1F: pointercount = 5; break;
                        case 0x3F: pointercount = 6; break;
                        case 0x7F: pointercount = 7; break;
                    }
                    Int32 commendedValue1 = commendedValue + (commendedValue - pointercount);
                    if (commendedValue1 < 0 || commendedValue1 > 0x7)
                    {
                        commendedValue1 = 0x04;
                    }
                    WriteLog($"0x17 commendedValue1:{commendedValue1}");
                    DAC9122_FIFO_Init(false, (UInt16)commendedValue1);
                }
            }
            else
            {
                DAC9122_FIFO_Init(false, (UInt16)commendedValue);
            }

            //FIFO Warning Flag
            Boolean flag_status = false;
            UInt32 warn_flag = ReadDACSpi(0x06);//EXPECT 0x00
            flag_status = ((warn_flag & 0x03) != (UInt16)(0x00));
            WriteLog($"0x06 flag_status:{flag_status} warn_flag:0x{Convert.ToString(warn_flag, 16)}");
            if (flag_status)
            {
                DAC9122_FIFO_Init(false, commendedValue);
            }
        }

        public static Boolean DAC9122_FIFO_Monitor()
        {
            UInt32 pointer = ReadDACSpi(0x19);
            Boolean pointer_status = false;
            pointer_status = (pointer != (UInt16)(0x07) || pointer != (UInt16)(0x0F) || pointer != (UInt16)(0x1F));
            return true;
        }

        /// <summary>
        /// 读取寄存器地址的值
        /// </summary>
        /// <param name="regAddr"></param>
        /// <param name="delayus"></param>
        /// <returns></returns>
        static UInt32 ReadAwgRegBySpi(ushort regAddr, int delayus = 0)
        {
            var readDataReg = (UInt32)ProcBdReg.R.Awg_data_awg_rd;
            HdIO.WriteReg(ProcBdReg.W.Awg_awg_wr_ctrl, 0x04);
            // 低8位地址
            ushort addrCtrl = (ushort)(regAddr & 0xffff);
            // cs为0时，发送一次，赋初值
            HdIO.WriteReg(ProcBdReg.W.Awg_awg_addr_ctrl, addrCtrl);
            // cs置1，再发送一次
            addrCtrl = (ushort)(regAddr | (0x0001 << 8));
            HdIO.WriteReg(ProcBdReg.W.Awg_awg_addr_ctrl, addrCtrl);
            HdIO.WriteReg(ProcBdReg.W.Awg_awg_wr_ctrl, 0x05);
            Thread.Sleep(1);
            HdIO.WriteReg(ProcBdReg.W.Awg_awg_wr_ctrl, 0x06);
            UInt32 data = HdIO.ReadReg(readDataReg);
            //HdIO.WriteReg(ProcBdReg.W.Awg_awg_wr_ctrl, 0x05);
            return data;
        }
        #endregion

    }
}
